solution_code:
#include <iostream>
#include <iomanip>

int main() {
    double value;
    std::cin >> value;

    int truncated = value;   // implicit double -> int conversion, truncates toward zero
    double error = value - static_cast<double>(truncated);

    std::cout << "Truncated: " << truncated << "\n";
    std::cout << "Error: " << std::fixed << std::setprecision(2) << error << "\n";
    return 0;
}

