#include <iostream>

int main() {
    int temp;
    std::cin >> temp;

    // Compare the original int directly against the short max value
    bool fits = (temp >= -32768 && temp <= 32767);

    std::cout << "Fits in short: " << (fits ? "yes" : "no") << "\n";
    return 0;
}
